    """
    Convert a list of Triple objects describing an artist (or related entity)
    into a single fluent English sentence.
    """
    if not triples:
        return ""

    # Main entity is the subject of the first triple
    main_subject = triples[0].subject

    # Helper to clean object strings
    def _clean(obj: str) -> str:
        return obj.strip('"')

    # Build a mapping from subject to its triples for quick lookup
    _subject_map: dict[str, list[Triple]] = {}
    for _t in triples:
        _subject_map.setdefault(_t.subject, []).append(_t)

    # Gather information about the main subject (subject of the first triple)
    _main_triples = _subject_map.get(main_subject, [])

    # Try to detect a primary genre for the main subject
    _genre_obj = None
    _other_main = []
    for _t in _main_triples:
        if _t.predicate == "genre":
            _genre_obj = _clean(_t.object)
        else:
            _other_main.append(_t)

    _sentences: list[str] = []

    if _genre_obj:
        # Information about the genre itself (stylistic origins, fusion genres, derivatives)
        _genre_triples = _subject_map.get(_genre_obj, [])
        _stylistic = [_clean(t.object) for t in _genre_triples if t.predicate == "stylisticOrigin"]
        _fusion = [_clean(t.object) for t in _genre_triples if t.predicate == "musicFusionGenre"]
        # Main sentence about the artist and their genre
        _main_sentence = f"{main_subject} performs {_genre_obj.lower()} music"
        if _stylistic:
            _main_sentence += f", which originated from {', '.join(_stylistic)}"
        if _fusion:
            _conj = " and" if _stylistic else ", which"
            _main_sentence += f"{_conj} has fusion genre {', '.join(_fusion)}"
        _main_sentence += "."
        _sentences.append(_main_sentence)

        # Derivative relations where the genre is the subject
        for _t in _genre_triples:
            if _t.predicate == "derivative":
                _obj = _clean(_t.object)
                _sentences.append(f"{_obj} is derived from {_genre_obj.lower()}.")
